def find_source_for_key(layers: list, key: str) -> str:
    """
    Given a list of (name, dict) layers ordered by precedence, find which layer
    the key came from (highest precedence that has the key).
    Returns layer name or None.
    """
    for layer_name, layer_dict in reversed(layers):
        if layer_dict and key in layer_dict:
            return layer_name
    return None


def deep_merge_with_sources(layers: list, warnings: list, path: str = "") -> dict:
    """
    Deep merge layers in order. layers is a list of (name, dict) tuples ordered by precedence.
    Records warnings when types conflict.
    Returns new dict with merge applied.
    """
    if not layers:
        return {}

    # Find the highest-precedence layer that has some content
    result = None
    for layer_name, layer_dict in reversed(layers):
        if layer_dict:
            result = dict(layer_dict)
            break

    if result is None:
        return {}

    # Now merge remaining layers with lower precedence into result
    # We need to find sources for warnings
    # For each key in result, figure out which layer it came from
    result_layers = []  # (name, dict) that contributed to result

    # Reorder layers: highest precedence first
    layers_ordered = list(reversed(layers))

    for layer_name, layer_dict in layers_ordered:
        if layer_dict is None:
            continue
        if not result_layers:
            # First layer (highest) contributes all its keys
            result_layers.append((layer_name, layer_dict))
            continue

        # For lower layers: only merge keys not already in result
        new_content = {}
        for key, val in layer_dict.items():
            if key not in result:
                result[key] = val
                new_content[key] = val
            else:
                # Key exists in both - need to merge deeply or detect type conflict
                base_val = result[key]
                base_type = get_json_type(base_val)
                override_type = get_json_type(val)

                current_path = f"{path}/{key}" if path else f"/{key}"

                # Both are objects -> deep merge
                if base_type == "object" and override_type == "object":
                    # Create a mini-layer list for deep merge
                    sub_layers = [(layer_name, val), ("_existing", base_val)]
                    merged_sub = deep_merge_with_sources(sub_layers, warnings, current_path)
                    result[key] = merged_sub
                elif base_type == "array" or override_type == "array":
                    # Arrays replace wholesale
                    if base_type != override_type:
                        # Find which layer base came from
                        loser_source = find_source_for_key(result_layers, key) or "lower layer"
                        warnings.append(f"CONFLICT {current_path} {layer_name} replaced {loser_source}")
                    result[key] = val
                elif base_type != override_type:
                    # Different types
                    loser_source = find_source_for_key(result_layers, key) or "lower layer"
                    warnings.append(f"CONFLICT {current_path} {layer_name} replaced {loser_source}")
                    result[key] = val
                else:
                    # Same type, scalars - replace
                    result[key] = val

                new_content[key] = val

        if new_content:
            result_layers.append((layer_name, new_content))

    return result

